#!/usr/bin/env python3 """ XAVIER OS - ENHANCED COSYVOICE TTS SERVICE Advanced emotional speech synthesis with character-specific voice profiles Runs as a microservice on port 3005, optimized for audiobook generation """ import os import sys import json import torch import torchaudio import io import argparse import traceback from pathlib import Path from tempfile import NamedTemporaryFile from typing import Dict, Optional, List # Flask for HTTP API try: from flask import Flask, request, send_file, jsonify from flask_cors import CORS except ImportError: print("❌ Flask not installed. Run: pip install flask flask-cors") sys.exit(1) # CosyVoice imports try: from cosyvoice.models.cosyvoice import CosyVoice from cosyvoice.utils.file_utils import load_wav except ImportError as e: print(f"⚠️ CosyVoice package not found: {e}") print("Make sure you're in the correct conda environment with CosyVoice installed") sys.exit(1) app = Flask(__name__) CORS(app) # Global model instance model = None device = "cuda" if torch.cuda.is_available() else "cpu" print(f"🎯 Using device: {device}") # ============================================================================ # 🎭 CHARACTER VOICE PROFILES # Each character type gets unique voice treatment # ============================================================================ CHARACTER_VOICE_PROFILES = { # Protagonist types 'hero': {'base_voice': 'ZhiYan', 'emotion_bias': {'happy': 0.3, 'neutral': 0.4, 'surprise': 0.2, 'angry': 0.1}, 'pitch_offset': 1, 'speed_factor': 1.05, 'description': 'Confident, clear, heroic tone'}, 'heroine': {'base_voice': 'Happy', 'emotion_bias': {'happy': 0.4, 'neutral': 0.3, 'sad': 0.2, 'surprise': 0.1}, 'pitch_offset': 2, 'speed_factor': 1.0, 'description': 'Warm, determined, compassionate'}, # Antagonist types 'villain': {'base_voice': 'Angry', 'emotion_bias': {'angry': 0.4, 'neutral': 0.3, 'sad': 0.2, 'fearful': 0.1}, 'pitch_offset': -2, 'speed_factor': 0.9, 'description': 'Dark, menacing, controlled intensity'}, 'manipulator': {'base_voice': 'Neutral', 'emotion_bias': {'neutral': 0.5, 'happy': 0.2, 'sad': 0.2, 'angry': 0.1}, 'pitch_offset': -1, 'speed_factor': 0.95, 'description': 'Smooth, calculating, deceptive'}, # Ally types 'mentor': {'base_voice': 'Neutral', 'emotion_bias': {'neutral': 0.5, 'happy': 0.2, 'sad': 0.2, 'surprise': 0.1}, 'pitch_offset': -1, 'speed_factor': 0.85, 'description': 'Wise, measured, authoritative'}, 'loyal_friend': {'base_voice': 'Happy', 'emotion_bias': {'happy': 0.5, 'neutral': 0.2, 'surprise': 0.2, 'fearful': 0.1}, 'pitch_offset': 1, 'speed_factor': 1.1, 'description': 'Enthusiastic, supportive, warm'}, 'comic_relief': {'base_voice': 'Happy', 'emotion_bias': {'happy': 0.6, 'surprise': 0.2, 'neutral': 0.1, 'sad': 0.1}, 'pitch_offset': 2, 'speed_factor': 1.15, 'description': 'Energetic, playful, exaggerated'}, # Special types 'narrator': {'base_voice': 'ZhiYan', 'emotion_bias': {'neutral': 0.6, 'happy': 0.15, 'sad': 0.1, 'surprise': 0.15}, 'pitch_offset': 0, 'speed_factor': 0.95, 'description': 'Clear, neutral, engaging storyteller'}, 'elder': {'base_voice': 'Sad', 'emotion_bias': {'sad': 0.3, 'neutral': 0.4, 'happy': 0.2, 'fearful': 0.1}, 'pitch_offset': -2, 'speed_factor': 0.8, 'description': 'Weathered, slow, wise'}, 'child': {'base_voice': 'Happy', 'emotion_bias': {'happy': 0.5, 'surprise': 0.3, 'neutral': 0.1, 'fearful': 0.1}, 'pitch_offset': 3, 'speed_factor': 1.1, 'description': 'Youthful, energetic, innocent'} } # ============================================================================ # 📚 BOOK-SPECIFIC VOICE PRESETS # Optimized voice settings for different genres # ============================================================================ BOOK_GENRE_PRESETS = { # LitRPG/System novels 'litrpg': {'narrator_style': 'ZhiYan', 'emotion_range': 'narrow', 'avg_speed': 1.05, 'description': 'Clear, game-like narration with status updates'}, # Cultivation novels 'cultivation': {'narrator_style': 'Neutral', 'emotion_range': 'wide', 'avg_speed': 0.9, 'description': 'Epic, philosophical tone with dramatic pauses'}, # Dark Fantasy 'dark_fantasy': {'narrator_style': 'Sad', 'emotion_range': 'moderate', 'avg_speed': 0.85, 'description': 'Gritty, atmospheric, foreboding'}, # Epic Fantasy 'epic_fantasy': {'narrator_style': 'ZhiYan', 'emotion_range': 'wide', 'avg_speed': 0.95, 'description': 'Grand, heroic, sweeping narrative'}, # Wuxia/Xianxia 'wuxia': {'narrator_style': 'Neutral', 'emotion_range': 'moderate', 'avg_speed': 0.9, 'description': 'Traditional, honor-bound, martial arts elegance'}, # Sci-Fi 'sci_fi': {'narrator_style': 'ZhiYan', 'emotion_range': 'moderate', 'avg_speed': 1.0, 'description': 'Technical, precise, futuristic'}, # Romance 'romance': {'narrator_style': 'Happy', 'emotion_range': 'wide', 'avg_speed': 0.95, 'description': 'Warm, emotional, relationship-focused'}, # Horror 'horror': {'narrator_style': 'Fearful', 'emotion_range': 'wide', 'avg_speed': 0.8, 'description': 'Tense, suspenseful, atmospheric dread'} } # ============================================================================ # 🎨 EMOTION MAPPING SYSTEM # Maps text sentiment to voice emotions # ============================================================================ EMOTION_KEYWORDS = { 'happy': ['joy', 'happy', 'cheerful', 'glad', 'pleased', 'delighted', 'excited', 'wonderful', 'great', 'excellent', 'amazing', 'fantastic'], 'sad': ['sad', 'sorrow', 'grief', 'mourning', 'tears', 'cry', 'depressed', 'miserable', 'heartbroken', 'tragic', 'loss', 'death'], 'angry': ['angry', 'fury', 'rage', 'wrath', 'irate', 'furious', 'annoyed', 'outraged', 'livid', 'hate', 'destroy', 'kill'], 'fearful': ['fear', 'afraid', 'scared', 'terrified', 'horrified', 'dread', 'panic', 'terror', 'nightmare', 'horror', 'threatening'], 'surprise': ['surprise', 'shock', 'astonished', 'amazed', 'stunned', 'incredible', 'unbelievable', 'unexpected', 'sudden', 'revealed'] } def detect_emotion_from_text(text: str) -> str: """Detect emotion from text content""" text_lower = text.lower() emotion_scores = { 'happy': 0, 'sad': 0, 'angry': 0, 'fearful': 0, 'surprise': 0 } for emotion, keywords in EMOTION_KEYWORDS.items(): for keyword in keywords: if keyword in text_lower: emotion_scores[emotion] += 1 # Get highest scoring emotion if max(emotion_scores.values()) > 0: return max(emotion_scores, key=emotion_scores.get) return 'neutral' def get_voice_for_context( context: str, character_type: str = 'narrator', genre: str = 'narrator' ) -> Dict: """ Get optimal voice settings based on context Args: context: The text being spoken character_type: Type of character (hero, villain, mentor, etc.) genre: Book genre for style adjustments Returns: Dictionary with voice parameters """ # Get base profile if character_type in CHARACTER_VOICE_PROFILES: profile = CHARACTER_VOICE_PROFILES[character_type] else: profile = CHARACTER_VOICE_PROFILES['narrator'] # Apply genre adjustments if genre in BOOK_GENRE_PRESETS: preset = BOOK_GENRE_PRESETS[genre] else: preset = BOOK_GENRE_PRESETS.get('narrator', {}) # Detect emotion from text detected_emotion = detect_emotion_from_text(context) # Calculate final voice settings return { 'base_voice': profile.get('base_voice', 'ZhiYan'), 'emotion': detected_emotion, 'pitch': profile.get('pitch_offset', 0), 'speed': profile.get('speed_factor', 1.0), 'style': character_type, 'description': profile.get('description', 'Standard narration') } # ============================================================================ # 🎙️ TTS GENERATION FUNCTIONS # ============================================================================ @app.route('/health', methods=['GET']) def health(): """Health check with detailed status""" return jsonify({ 'status': 'ok', 'service': 'Enhanced CosyVoice TTS', 'model_loaded': model is not None, 'device': device, 'available_voices': list(CHARACTER_VOICE_PROFILES.keys()), 'genre_presets': list(BOOK_GENRE_PRESETS.keys()), 'supported_emotions': list(EMOTION_KEYWORDS.keys()) }) @app.route('/api/tts', methods=['GET', 'POST']) def tts(): """ Enhanced TTS endpoint with character-aware voice synthesis Parameters: - text (required): Text to synthesize - emotion (optional): Override detected emotion - character_type (optional): Character type for voice profile - genre (optional): Book genre for style adjustment - speed (optional): Speed multiplier - pitch (optional): Pitch offset """ try: # Parse request if request.method == 'GET': text = request.args.get('text') emotion = request.args.get('emotion') character_type = request.args.get('character_type', 'narrator') genre = request.args.get('genre', 'narrator') speed = request.args.get('speed') pitch = request.args.get('pitch') else: data = request.get_json() or {} text = data.get('text') emotion = data.get('emotion') character_type = data.get('character_type', 'narrator') genre = data.get('genre', 'narrator') speed = data.get('speed') pitch = data.get('pitch') if not text: return jsonify({'error': 'text parameter required'}), 400 if not model: return jsonify({'error': 'Model not loaded'}), 503 # Get voice settings voice_settings = get_voice_for_context(text, character_type, genre) # Override with manual settings if provided if emotion: voice_settings['emotion'] = emotion if speed: voice_settings['speed'] = float(speed) if pitch: voice_settings['pitch'] = int(pitch) print(f"🎵 TTS: text='{text[:50]}...' emotion={voice_settings['emotion']} " f"character={character_type} genre={genre}") # Generate speech output_file = NamedTemporaryFile(suffix='.wav', delete=False) output_path = output_file.name output_file.close() try: # Use CosyVoice inference tts_output = model.inference_zero_shot( tts_text=text, prompt_speech_16k=None, speaker_name=voice_settings['base_voice'], style=voice_settings['emotion'], stream=False ) # Process audio if isinstance(tts_output, dict): audio_tensor = tts_output.get('tts_speech') else: audio_tensor = tts_output if audio_tensor is not None: # Apply speed adjustment if needed if voice_settings['speed'] != 1.0: sample_rate = 22050 new_length = int(audio_tensor.shape[-1] / voice_settings['speed']) audio_tensor = torch.nn.functional.interpolate( audio_tensor.unsqueeze(0).unsqueeze(0) if audio_tensor.dim() == 1 else audio_tensor.unsqueeze(0), size=new_length, mode='linear' ).squeeze() # Save audio torchaudio.save(output_path, audio_tensor.unsqueeze(0) if audio_tensor.dim() == 1 else audio_tensor, 22050) # Read and return with open(output_path, 'rb') as f: audio_data = f.read() os.unlink(output_path) response = send_file( io.BytesIO(audio_data), mimetype='audio/wav', as_attachment=False, download_name='speech.wav' ) response.headers['X-Voice-Emotion'] = voice_settings['emotion'] response.headers['X-Voice-Character'] = character_type response.headers['X-Voice-Genre'] = genre return response else: raise Exception("No audio output from model") except Exception as e: if os.path.exists(output_path): try: os.unlink(output_path) except: pass raise e except Exception as e: print(f"❌ TTS Error: {e}") print(traceback.format_exc()) return jsonify({'error': 'TTS generation failed', 'details': str(e)}), 500 @app.route('/api/voices', methods=['GET']) def get_voices(): """List all available voice profiles and presets""" return jsonify({ 'character_profiles': { k: {'description': v.get('description', ''), 'base_voice': v.get('base_voice', 'ZhiYan')} for k, v in CHARACTER_VOICE_PROFILES.items() }, 'genre_presets': { k: {'description': v.get('description', ''), 'narrator_style': v.get('narrator_style', 'ZhiYan')} for k, v in BOOK_GENRE_PRESETS.items() }, 'supported_emotions': list(EMOTION_KEYWORDS.keys()) }) @app.route('/api/generate-voice', methods=['POST']) def generate_voice(): """ Generate voice with full control over parameters Useful for audiobook production with character-specific voices """ try: data = request.get_json() text = data.get('text') character_profile = data.get('character_profile') emotion = data.get('emotion', 'neutral') speed = data.get('speed', 1.0) pitch = data.get('pitch', 0) if not text: return jsonify({'error': 'text required'}), 400 # Get character profile settings if character_profile and character_profile in CHARACTER_VOICE_PROFILES: settings = CHARACTER_VOICE_PROFILES[character_profile] base_voice = settings.get('base_voice', 'ZhiYan') speed = settings.get('speed_factor', speed) pitch = settings.get('pitch_offset', pitch) else: base_voice = 'ZhiYan' print(f"🎵 Generating voice: character={character_profile} emotion={emotion}") # Generate output_file = NamedTemporaryFile(suffix='.wav', delete=False) output_path = output_file.name output_file.close() try: tts_output = model.inference_zero_shot( tts_text=text, prompt_speech_16k=None, speaker_name=base_voice, style=emotion, stream=False ) if isinstance(tts_output, dict): audio_tensor = tts_output.get('tts_speech') else: audio_tensor = tts_output if audio_tensor is not None: torchaudio.save(output_path, audio_tensor.unsqueeze(0) if audio_tensor.dim() == 1 else audio_tensor, 22050) with open(output_path, 'rb') as f: audio_data = f.read() os.unlink(output_path) response = send_file( io.BytesIO(audio_data), mimetype='audio/wav' ) response.headers['X-Character'] = character_profile response.headers['X-Emotion'] = emotion return response else: raise Exception("No audio output") except Exception as e: if os.path.exists(output_path): try: os.unlink(output_path) except: pass raise e except Exception as e: print(f"❌ Generate Voice Error: {e}") return jsonify({'error': str(e)}), 500 def main(): parser = argparse.ArgumentParser(description='Enhanced CosyVoice TTS Service') parser.add_argument('--port', type=int, default=3005, help='Port to run on (default: 3005)') parser.add_argument('--model-path', default='pretrained_models/CosyVoice2-0.5B', help='Path to CosyVoice model') parser.add_argument('--host', default='0.0.0.0', help='Host to bind to') parser.add_argument('--debug', action='store_true', help='Enable debug mode') args = parser.parse_args() global model print("=" * 70) print("🎙️ ENHANCED COSYVOICE TTS SERVICE - Xavier OS") print("=" * 70) print(f"📍 Device: {device}") print(f"📁 Model path: {args.model_path}") print(f"🌐 Running on: http://{args.host}:{args.port}") print("") print("Character Voice Profiles Available:") for profile_name, profile_data in CHARACTER_VOICE_PROFILES.items(): print(f"  - {profile_name}: {profile_data.get('description', '')}") print("") print("Genre Presets Available:") for genre_name, genre_data in BOOK_GENRE_PRESETS.items(): print(f"  - {genre_name}: {genre_data.get('description', '')}") print("=" * 70) # Load model try: print(f"🔄 Loading CosyVoice model from {args.model_path}...") model = CosyVoice(args.model_path) print("✅ Model loaded successfully") except Exception as e: print(f"❌ Failed to load model: {e}") print(traceback.format_exc()) sys.exit(1) print(f"🚀 Starting server...") app.run(host=args.host, port=args.port, debug=args.debug, threaded=True) if __name__ == '__main__': main() 